     1→---
     2→import Container from "../ui/Container.astro";
     3→import HeroAnimation from "./HeroAnimation";
     4→import ScrollIndicator from "../ui/ScrollIndicator";
     5→
     6→interface Props {
     7→  title: string;
     8→  subtitle?: string;
     9→  backgroundImage?: string;
    10→  showScrollIndicator?: boolean;
    11→  scrollTargetId?: string;
    12→}
    13→
    14→const {
    15→  title,
    16→  subtitle,
    17→  backgroundImage = "/images/hero-bg.jpg",
    18→  showScrollIndicator = true,
    19→  scrollTargetId = "services",
    20→} = Astro.props;
    21→---
    22→
    23→<section
    24→  class="relative min-h-screen flex items-center justify-center overflow-hidden"
    25→  aria-label="ヒーローセクション"
    26→>
    27→  {/* Background Image with Overlay */}
    28→  <div class="absolute inset-0 z-0">
    29→    <div
    30→      class="absolute inset-0 bg-cover bg-center bg-no-repeat"
    31→      style={`background-image: url('${backgroundImage}')`}
    32→      role="img"
    33→      aria-label="背景画像"
    34→    >
    35→    </div>
    36→    {/* Gradient Overlay for contrast */}
    37→    <div class="absolute inset-0 bg-gradient-to-b from-black/60 via-black/40 to-black/60"></div>
    38→  </div>
    39→
    40→  {/* Content */}
    41→  <Container class="relative z-10 text-center py-20">
    42→    <HeroAnimation client:visible>
    43→      <h1 class="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-white leading-tight mb-6">
    44→        {title}
    45→      </h1>
    46→      {subtitle && (
    47→        <p class="text-lg sm:text-xl md:text-2xl text-white/90 max-w-3xl mx-auto mb-8">
    48→          {subtitle}
    49→        </p>
    50→      )}
    51→      <slot />
    52→    </HeroAnimation>
    53→  </Container>
    54→
    55→  {/* Scroll Indicator */}
    56→  {showScrollIndicator && (
    57→    <div class="absolute bottom-8 left-1/2 -translate-x-1/2 z-10">
    58→      <ScrollIndicator client:visible targetId={scrollTargetId} />
    59→    </div>
    60→  )}
    61→</section>
    62→

